import{m as s}from"./module.esm-VSGE1p6w.js";window.authLogic=()=>({name:"",email:"",password:"",loading:!1,async signup(){this.loading=!0;try{const e=await fetch("/api/auth/signup",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({name:this.name,email:this.email,password:this.password})}),t=await e.json();if(!e.ok)throw new Error(t.message||"Signup failed");localStorage.setItem("DOTTIE_token",t.token),localStorage.setItem("DOTTIE_user",JSON.stringify({name:t.name,id:t.userId})),window.dispatchEvent(new CustomEvent("notify",{detail:{message:"Signed up successfully",type:"success"}})),setTimeout(()=>window.location.href="/index.html",1500)}catch(e){window.dispatchEvent(new CustomEvent("notify",{detail:{message:e.message,type:"error"}}))}finally{this.loading=!1}}});window.Alpine=s;s.start();
